import * as React from 'react';
import Box from '@mui/material/Box';
import AppBar from '@mui/material/AppBar';
import Button from '@mui/material/Button';
import Grid from '@mui/material/Grid';
// import Link from '@mui/material/Link';
import { styled } from '@mui/material/styles';
// import { useNavigate } from 'react-router-dom';

// const LinkButton = styled(Button)(() => ({
//   width: '90%',
//   height: '100%',
//   borderRadius: '0px',
//   "&:hover": {
//     background: '#f5f5f5'
//   },
//   "&:active": {
//     background: '#e3e3e3'
//   },
//   "&:focus": {
//     borderBottom: '0.5px solid #333'
//   },
// }));

const NavButton = styled(Button)(() => ({
	minWidth: '0px',
  // width: '100%',
	padding: '0px',
  margin: '0px 0px',
  border: 'none',
  background: 'none',
  position: 'relative',
  display: 'flex',
  fontWeight: 400,
  fontSize: '14px',
  gap: '0.5rem',
  alignItems: 'center',
  // textAlign: 'center',

	'p': {
		margin: 0,
		position: 'relative',
		color: '#32292F',
	},

	'&::after': {
		position: 'absolute',
		content: '""',
		width: 0,
		left: 0,
		bottom: '-7px',
		background: '#6E7DAB',
		height: '2px',
		transition: '0.3s ease-out',
	},

	'&:hover': {
		background: 'none',
	},

	'&:hover p': {
		color: '#6E7DAB',
		transition: '0.5s ease-in-out',
	},

	'&:hover::after': {
		width: '100%',
	},
}))

const NavButtonActive = styled(Button)(() => ({
	minWidth: '0px',
	padding: '0px',
  margin: '0px 10px',
  border: 'none',
  background: 'none',
  position: 'relative',
  display: 'flex',
  fontWeight: 400,
  fontSize: '14px',
  gap: '0.5rem',
  alignItems: 'center',

	'p': {
		margin: 0,
		position: 'relative',
		color: '#6E7DAB',
	},

	'&::after': {
		position: 'absolute',
		content: '""',
		width: 0,
		left: 0,
		bottom: '-7px',
		background: '#6E7DAB',
		height: '2px',
		transition: '0.3s ease-out',
	},

	'&:hover': {
		background: 'none',
	},

}))

const collections = ['Daylight', 'Dust', 'Escape', 'Illusion', 'Mountains', 'Nice Dream', 'Rose Gold', 'Stay', 'Times', 'Voyages']

function SubHeader ({ click, setClick }) {
  const [ activeLink, setActiveLink ] = React.useState('');
  const galleries = [];

  const handleClick = (name) => {
    // setClick(name);
		setActiveLink(name);
		// console.log('link', name);
		// navigate('/' + link);
    // setClick(name.trim().replace(/\s/g, ''));
	};

  collections.forEach((gallery) => {
    const name = gallery.toLowerCase().trim().replace(/\s/g, '');

    galleries.push(
      <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '', marginTop: '12px', display: 'flex', justifyContent: 'center' }} key={'item_' + name}>
        {/* <NavButton
          onClick={() => setClick(gallery.trim().replace(/\s/g, ''))}
          color='inherit'
          id={'button_' + name}
          disableRipple='true'
        >
          <p>{gallery}</p>
        </NavButton> */}

        {/*
          click is the active gallery
          highlight this active gallery button
          by appending Active Button for only this link and
          by appending Inactive Button for other links
        */}

        { console.log('click == activeLink', click, activeLink) }

        {
          click === activeLink ?

          <NavButtonActive
            onClick={() => setClick(gallery.trim().replace(/\s/g, ''))}
            color='inherit'
            id={'button_' + name}
            disableRipple='true'
          >
            <p>{gallery}</p>
          </NavButtonActive> :

          <NavButton
            onClick={() => setActiveLink(gallery.trim().replace(/\s/g, ''))}
            color='inherit'
            id={'button_' + name}
            disableRipple='true'
          >
            <p>{gallery}</p>
          </NavButton>
        }
      </Grid>
    )
  })

  React.useEffect(() => {
    console.log('re-render');
  }, [])

  return (
    <>
      <AppBar
        position='static'
        color='inherit'
        sx={{ boxShadow: '0px 0px 0px #e3e3e3' }}
      >
        <Box
          sx={{ display: 'block', margin: '74px 10% 30px' }} // original 86px 10% 30px
        >
          <Grid container columns={{ xs: 2, sm: 5, lg: 10 }} gap={0} sx={{  }}>
            {galleries}
          </Grid>
        </Box>
      </AppBar>
    </>
  )
}

export default SubHeader;
